const sshRaw = $input.first().json.stdout || '';
const maintSplit = sshRaw.split('---MAINT---');
const stateJson = (maintSplit[0] || '').trim();
const maintRaw = (maintSplit[1] || 'NONE').trim();
let maintenanceActive = false;
let maintenanceInfo = null;
if (maintRaw !== 'NONE' && maintRaw !== '') {
  try { maintenanceInfo = JSON.parse(maintRaw); maintenanceActive = true; }
  catch(e) { maintenanceActive = true; maintenanceInfo = { reason: maintRaw }; }
}
if (maintenanceActive) {
  const stateB64 = Buffer.from(stateJson || '{}').toString('base64');
  return [{ json: { hasContent: false, needsYtIssue: false, isRepeat: false, shouldEscalate: false, target: '', targetDns: '', site: '', stateB64, maintenanceSuppressed: true, maintenanceReason: maintenanceInfo?.reason || 'scheduled' }}];
}
const webhookData = $('Security Webhook').first().json;
let body;
if (webhookData.body && typeof webhookData.body === 'object' && webhookData.body.body) { body = webhookData.body.body; }
else if (webhookData.body && typeof webhookData.body === 'object') { body = webhookData.body; }
else { body = webhookData; }
if (typeof body === 'string') { try { body = JSON.parse(body); } catch(e) { body = {}; } }
const sd = $getWorkflowStaticData('global');
if (!sd.processedScans) sd.processedScans = {};
if (!sd.targetIssues) sd.targetIssues = {};
if (Object.keys(sd.processedScans).length === 0 && Object.keys(sd.targetIssues).length === 0) {
  if (stateJson) {
    try { const loaded = JSON.parse(stateJson); if (loaded && typeof loaded === 'object') { sd.processedScans = loaded.processedScans || {}; sd.targetIssues = loaded.targetIssues || {}; } } catch(e) {}
  }
}
if (body.action === 'register' && body.target && body.issueId) {
  sd.targetIssues[body.target] = { issueId: body.issueId, registeredAt: Date.now() };
  const state = { processedScans: sd.processedScans, targetIssues: sd.targetIssues };
  const stateB64 = Buffer.from(JSON.stringify(state)).toString('base64');
  const shouldPostBaselinePoll = body.inBaseline === false && body.finding && body.port && body.scanner;
  return [{ json: { hasContent: false, stateB64, target: body.target, shouldPostBaselinePoll: !!shouldPostBaselinePoll, pollTarget: body.target || '', pollPort: body.port || '', pollFinding: body.finding || '', pollScanner: body.scanner || '', pollIssueId: body.issueId || '' } }];
}
const scanner = body.scanner || '';
const scanDate = body.scan_date || '';
const target = body.target || '';
const targetDns = body.target_dns || target;
const site = (body.site || '').toUpperCase();
const scanType = body.scan_type || 'unknown';
const baselineDiff = body.baseline_diff === true;
const findings = Array.isArray(body.findings) ? body.findings : [];
const summary = body.summary || {};
if (site && site !== 'NL') {
  const state = { processedScans: sd.processedScans, targetIssues: sd.targetIssues };
  const stateB64 = Buffer.from(JSON.stringify(state)).toString('base64');
  return [{ json: { hasContent: false, stateB64, target, targetDns, site, suppressed: true, suppressReason: 'wrong_site' }}];
}
const dedupKey = scanner + ':' + target + ':' + scanDate;
if (sd.processedScans[dedupKey]) {
  const state = { processedScans: sd.processedScans, targetIssues: sd.targetIssues };
  const stateB64 = Buffer.from(JSON.stringify(state)).toString('base64');
  return [{ json: { hasContent: false, stateB64, target, targetDns, site, suppressed: true, suppressReason: 'dedup' }}];
}
sd.processedScans[dedupKey] = Date.now();
if (!baselineDiff || findings.length === 0) {
  const state = { processedScans: sd.processedScans, targetIssues: sd.targetIssues };
  const stateB64 = Buffer.from(JSON.stringify(state)).toString('base64');
  return [{ json: { hasContent: false, stateB64, target, targetDns, site, scanType, cleanScan: true }}];
}
const critFindings = findings.filter(f => f.severity === 'critical');
const highFindings = findings.filter(f => f.severity === 'high');
const critHighCount = critFindings.length + highFindings.length;
const highestSev = critFindings.length > 0 ? 'critical' : (highFindings.length > 0 ? 'high' : 'medium');
const targetEntry = sd.targetIssues[target];
const existingIssueId = targetEntry ? targetEntry.issueId || '' : '';
const isRepeat = !!existingIssueId;
const needsYtIssue = critHighCount > 0;
const shouldEscalate = critFindings.length > 0;
const sevEmoji = { critical: '\ud83d\udd34', high: '\ud83d\udfe0', medium: '\ud83d\udfe1' };
let fText = '';
let fHtml = '';
for (const f of findings) {
  const em = sevEmoji[f.severity] || '\u26aa';
  const ps = f.port ? ', port ' + f.port : '';
  fText += em + ' ' + (f.severity || 'unknown').toUpperCase() + ': ' + f.title + ' \u2014 ' + f.detail + ' (' + f.tool + ps + ')\n';
  fHtml += em + ' <b>' + (f.severity || 'unknown').toUpperCase() + '</b>: <code>' + f.title + '</code> \u2014 ' + f.detail + ' <i>(' + f.tool + ps + ')</i><br>';
}
const sumText = 'Targets: ' + (summary.targets_scanned || '?') + ' | New: ' + (summary.new_findings || findings.length) + ' | Ports: ' + (summary.total_open_ports || '?') + ' | Nuclei: ' + (summary.nuclei_hits || 0) + ' | TLS: ' + (summary.tls_issues || 0);
const matrixBody = '\ud83d\udd12 [Security] NEW FINDINGS: ' + targetDns + ' (' + target + ')\nScanner: ' + scanner + ' | ' + scanType + ' | ' + scanDate + '\n\n' + fText + '\n' + sumText;
const matrixHtml = '<b>\ud83d\udd12 [Security] NEW FINDINGS:</b> <code>' + targetDns + '</code> (' + target + ')<br><small>Scanner: ' + scanner + ' | ' + scanType + ' | ' + scanDate + '</small><br><br>' + fHtml + '<br><small>' + sumText + '</small>';
const topFinding = critFindings[0] || highFindings[0] || findings[0];
const ytSummary = 'Security: ' + topFinding.title + ' on ' + targetDns;
let ytDesc = '**Security Scanner Alert**\n\n**Target:** ' + targetDns + ' (' + target + ')\n**Scanner:** ' + scanner + '\n**Scan Date:** ' + scanDate + '\n**Scan Type:** ' + scanType + '\n\n**Findings:**\n';
for (const f of findings.filter(ff => ff.severity === 'critical' || ff.severity === 'high')) {
  ytDesc += '- **' + f.severity.toUpperCase() + ':** ' + f.title + ' \u2014 ' + f.detail + ' (' + f.tool + (f.port ? ', port ' + f.port : '') + ')\n';
  if (f.evidence) ytDesc += '  Evidence: `' + f.evidence + '`\n';
}
ytDesc += '\n' + sumText;
const commentText = 'New security scan findings (' + scanDate + '):\n\n' + findings.filter(ff => ff.severity === 'critical' || ff.severity === 'high').map(f => '- ' + f.severity.toUpperCase() + ': ' + f.title + ' \u2014 ' + f.detail).join('\n') + '\n\nScanner: ' + scanner + ' (' + scanType + ')';
const now = Date.now();
for (const k of Object.keys(sd.processedScans)) { if (now - sd.processedScans[k] > 2592000000) delete sd.processedScans[k]; }
for (const t of Object.keys(sd.targetIssues)) { if (sd.targetIssues[t].registeredAt && now - sd.targetIssues[t].registeredAt > 7776000000) delete sd.targetIssues[t]; }
const state = { processedScans: sd.processedScans, targetIssues: sd.targetIssues };
const stateB64 = Buffer.from(JSON.stringify(state)).toString('base64');
return [{ json: { hasContent: true, target, targetDns, site, scanner, scanDate, scanType, highestSev, critHighCount, needsYtIssue, existingIssueId, isRepeat, shouldEscalate, matrixBody, matrixHtml, ytSummary, ytDesc, commentText, fText, stateB64 }}];

const parseData = $('Parse Scan').first().json;
const ytResponse = $input.first().json;
const issueId = ytResponse.idReadable || '';
const target = parseData.target;
const sd = $getWorkflowStaticData('global');
if (!sd.targetIssues) sd.targetIssues = {};
if (issueId) {
  sd.targetIssues[target] = { issueId: issueId, registeredAt: Date.now() };
}
const state = { processedScans: sd.processedScans || {}, targetIssues: sd.targetIssues };
const stateB64 = Buffer.from(JSON.stringify(state)).toString('base64');
return [{ json: { ...parseData, registeredIssueId: issueId, stateB64 }}];

const parseAlert = $('Parse Scan').first().json;
const ytResponse = $input.first().json;
let repeatAction = 'comment';
let ytState = 'unknown';
try {
  const customFields = ytResponse.customFields || [];
  const stateField = customFields.find(f => f.name === 'State');
  if (stateField && stateField.value) {
    ytState = stateField.value.name || 'unknown';
  }
} catch(e) {
  ytState = 'unknown';
}
if (!ytResponse.id && !ytResponse.idReadable) {
  repeatAction = 'new';
} else if (ytState === 'Done' || ytState === 'Cancelled' || ytState === 'Duplicate') {
  repeatAction = 'new';
  const sd = $getWorkflowStaticData('global');
  if (sd.targetIssues && sd.targetIssues[parseAlert.target]) {
    sd.targetIssues[parseAlert.target].issueId = null;
  }
} else if (ytState === 'To Verify') {
  repeatAction = 'reopen';
} else {
  repeatAction = 'comment';
}
return [{ json: { ...parseAlert, repeatAction, ytState } }];

